import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const UserSignup = () => {
    const navigate = useNavigate();
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        phone: '',
        password: '',
        confirmPassword: ''
    });
    const [error, setError] = useState('');

    const handleSubmit = (e) => {
        e.preventDefault();
        if (formData.password !== formData.confirmPassword) {
            setError('Passwords do not match');
            return;
        }
        if (formData.name && formData.email && formData.phone && formData.password) {
            // Demo signup - in real app, call API
            localStorage.setItem('userToken', 'demo-token');
            localStorage.setItem('userEmail', formData.email);
            localStorage.setItem('userName', formData.name);
            navigate('/user-dashboard');
        } else {
            setError('Please fill all fields');
        }
    };

    return ( <
        div className = "min-h-screen bg-gradient-to-b from-gray-900 to-gray-800 flex items-center justify-center py-12 px-4" >
        <
        div className = "bg-gray-800 rounded-xl p-8 max-w-md w-full" >
        <
        div className = "text-center mb-8" >
        <
        div className = "flex justify-center mb-4" >
        <
        span className = "text-red-600 text-5xl" > 🎬 < /span> <
        /div> <
        h2 className = "text-3xl font-bold text-white" > Create Account < /h2> <
        p className = "text-gray-400 mt-2" > Sign up to start booking movies < /p> <
        /div>

        {
            error && ( <
                div className = "bg-red-600 text-white p-3 rounded-lg mb-4" > { error } <
                /div>
            )
        }

        <
        form onSubmit = { handleSubmit } >
        <
        div className = "mb-4" >
        <
        label className = "block text-gray-300 mb-2" > Full Name < /label> <
        input type = "text"
        value = { formData.name }
        onChange = {
            (e) => setFormData({...formData, name: e.target.value }) }
        className = "w-full px-4 py-2 bg-gray-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
        placeholder = "Enter your full name"
        required /
        >
        <
        /div>

        <
        div className = "mb-4" >
        <
        label className = "block text-gray-300 mb-2" > Email Address < /label> <
        input type = "email"
        value = { formData.email }
        onChange = {
            (e) => setFormData({...formData, email: e.target.value }) }
        className = "w-full px-4 py-2 bg-gray-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
        placeholder = "Enter your email"
        required /
        >
        <
        /div>

        <
        div className = "mb-4" >
        <
        label className = "block text-gray-300 mb-2" > Phone Number < /label> <
        input type = "tel"
        value = { formData.phone }
        onChange = {
            (e) => setFormData({...formData, phone: e.target.value }) }
        className = "w-full px-4 py-2 bg-gray-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
        placeholder = "Enter your phone number"
        required /
        >
        <
        /div>

        <
        div className = "mb-4" >
        <
        label className = "block text-gray-300 mb-2" > Password < /label> <
        input type = "password"
        value = { formData.password }
        onChange = {
            (e) => setFormData({...formData, password: e.target.value }) }
        className = "w-full px-4 py-2 bg-gray-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
        placeholder = "Create a password"
        required /
        >
        <
        /div>

        <
        div className = "mb-6" >
        <
        label className = "block text-gray-300 mb-2" > Confirm Password < /label> <
        input type = "password"
        value = { formData.confirmPassword }
        onChange = {
            (e) => setFormData({...formData, confirmPassword: e.target.value }) }
        className = "w-full px-4 py-2 bg-gray-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
        placeholder = "Confirm your password"
        required /
        >
        <
        /div>

        <
        button type = "submit"
        className = "w-full bg-red-600 text-white py-3 rounded-lg hover:bg-red-700 transition font-semibold" >
        Sign Up <
        /button> <
        /form>

        <
        div className = "mt-6 text-center" >
        <
        p className = "text-gray-400" >
        Already have an account ? { ' ' } <
        button onClick = {
            () => navigate('/user-login') }
        className = "text-red-500 hover:text-red-400" >
        Login <
        /button> <
        /p> <
        button onClick = {
            () => navigate('/') }
        className = "text-gray-400 hover:text-white mt-4 block" > ←Back to Home <
        /button> <
        /div> <
        /div> <
        /div>
    );
};

export default UserSignup;
